// @ts-nocheck
import { serve } from "https://deno.land/std@0.177.0/http/server.ts";
import { createClient } from "https://esm.sh/@supabase/supabase-js@2.45.0";
import { corsHeaders } from "../_shared/cors.ts";
import { isUrlSafe } from "../_shared/ssrf_validator.ts";
import { parseProductHtml } from "../_shared/html_parser.ts";

const supabaseUrl = Deno.env.get("SUPABASE_URL") || "";
const supabaseServiceKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY") || "";

const supabase = createClient(supabaseUrl, supabaseServiceKey);

serve(async (req) => {
  if (req.method === "OPTIONS") {
    return new Response("ok", { headers: corsHeaders });
  }

  try {
    const { sessaoId, sessionToken, url, action, images } = await req.json();

    if (!sessaoId || !sessionToken) {
      return new Response(JSON.stringify({ error: "Sessão não informada" }), {
        status: 401,
        headers: { ...corsHeaders, "Content-Type": "application/json" },
      });
    }

    // Authenticate
    const { data: actorData, error: authError } = await supabase.rpc(
      "gsa_admin_authorize_product_url_import",
      {
        p_sessao_id: sessaoId,
        p_session_token: sessionToken,
      }
    );

    if (authError || !actorData) {
      return new Response(JSON.stringify({ error: authError?.message || "Sessão inválida ou sem permissão" }), {
        status: 403,
        headers: { ...corsHeaders, "Content-Type": "application/json" },
      });
    }

    if (action === "analyze") {
      if (!url || !isUrlSafe(url)) {
        return new Response(JSON.stringify({ error: "URL inválida ou não permitida" }), {
          status: 400,
          headers: { ...corsHeaders, "Content-Type": "application/json" },
        });
      }

      // Fetch
      const controller = new AbortController();
      const timeoutId = setTimeout(() => controller.abort(), 10000);

      let response: Response;
      try {
        response = await fetch(url, {
          signal: controller.signal,
          headers: {
            "Accept": "text/html,application/xhtml+xml",
            "User-Agent": "Mozilla/5.0 (compatible; GSA-Store-Bot/1.0)",
          },
        });
      } catch (e: any) {
        clearTimeout(timeoutId);
        if (e.name === 'AbortError') {
           return new Response(JSON.stringify({ error: "Tempo limite excedido ao consultar URL" }), {
             status: 408, headers: { ...corsHeaders, "Content-Type": "application/json" }
           });
        }
        return new Response(JSON.stringify({ error: "Falha ao consultar a URL" }), {
          status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" }
        });
      }
      clearTimeout(timeoutId);

      const contentType = response.headers.get("content-type") || "";
      if (!contentType.includes("text/html")) {
        return new Response(JSON.stringify({ error: "A URL não retornou conteúdo HTML válido" }), {
          status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" }
        });
      }

      const text = await response.text();
      if (text.length > 2000000) {
        return new Response(JSON.stringify({ error: "Conteúdo da página muito grande (>2MB)" }), {
          status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" }
        });
      }

      const parsed = parseProductHtml(text, response.url || url);

      // Log action
      await supabase.from("sistema_logs").insert({
        acao: "IMPORTAR_DADOS_PRODUTO_URL",
        detalhes: JSON.stringify({
          url_consultada: new URL(url).hostname,
          campos_encontrados: Object.keys(parsed.origem_campos),
          status: "sucesso"
        }),
        ator_tipo: actorData.ator_tipo,
        ator_id: actorData.ator_id,
        ator_nome: actorData.ator_nome,
      });

      return new Response(JSON.stringify({
        success: true,
        data: {
          ...parsed,
          url_original: url,
          url_final: response.url || url,
          avisos: []
        }
      }), {
        headers: { ...corsHeaders, "Content-Type": "application/json" },
      });

    } else if (action === "copy_images") {
      if (!Array.isArray(images) || images.length === 0) {
         return new Response(JSON.stringify({ error: "Nenhuma imagem informada" }), { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } });
      }

      const uploadedUrls: string[] = [];
      const failedUrls: string[] = [];

      for (const imgUrl of images) {
        if (!isUrlSafe(imgUrl)) {
           failedUrls.push(imgUrl);
           continue;
        }

        try {
          const controller = new AbortController();
          const timeoutId = setTimeout(() => controller.abort(), 10000);
          const imgRes = await fetch(imgUrl, { signal: controller.signal });
          clearTimeout(timeoutId);

          if (!imgRes.ok) {
            failedUrls.push(imgUrl);
            continue;
          }

          const blob = await imgRes.blob();
          if (blob.size > 5000000) { // 5MB
            failedUrls.push(imgUrl);
            continue;
          }

          const cType = blob.type;
          if (!['image/jpeg', 'image/png', 'image/webp'].includes(cType)) {
             failedUrls.push(imgUrl);
             continue;
          }

          const ext = cType.split('/')[1];
          const fileName = `imports/produtos/${crypto.randomUUID()}.${ext}`;

          const { data: uploadData, error: uploadError } = await supabase.storage
            .from('gsa-store-images')
            .upload(fileName, blob, {
              contentType: cType,
              upsert: true
            });

          if (uploadError || !uploadData) {
            failedUrls.push(imgUrl);
          } else {
            const { data: publicData } = supabase.storage.from('gsa-store-images').getPublicUrl(fileName);
            uploadedUrls.push(publicData.publicUrl);
          }
        } catch (e) {
          failedUrls.push(imgUrl);
        }
      }

      await supabase.from("sistema_logs").insert({
        acao: "IMPORTAR_DADOS_PRODUTO_URL",
        detalhes: JSON.stringify({
          imagens_copiadas: uploadedUrls.length,
          imagens_falhas: failedUrls.length,
          status: "copia_imagens"
        }),
        ator_tipo: actorData.ator_tipo,
        ator_id: actorData.ator_id,
        ator_nome: actorData.ator_nome,
      });

      return new Response(JSON.stringify({
        success: true,
        data: {
          uploaded: uploadedUrls,
          failed: failedUrls
        }
      }), { headers: { ...corsHeaders, "Content-Type": "application/json" } });

    } else {
      return new Response(JSON.stringify({ error: "Ação inválida" }), {
        status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" }
      });
    }

  } catch (error: any) {
    return new Response(JSON.stringify({ error: error.message || "Erro interno do servidor" }), {
      status: 500,
      headers: { ...corsHeaders, "Content-Type": "application/json" },
    });
  }
});

export const corsHeaders = {
  'Access-Control-Allow-Origin': '*',
  'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
  'Access-Control-Allow-Methods': 'POST, GET, OPTIONS, PUT, DELETE',
};

export function isUrlSafe(urlStr: string): boolean {
  try {
    const url = new URL(urlStr);

    if (url.protocol !== 'http:' && url.protocol !== 'https:') {
      return false;
    }

    if (url.username || url.password) {
      return false;
    }

    const hostname = url.hostname.toLowerCase();

    // Block localhost and standard private ranges
    if (
      hostname === 'localhost' ||
      hostname.startsWith('127.') ||
      hostname.startsWith('10.') ||
      hostname.startsWith('192.168.') ||
      hostname.startsWith('169.254.') ||
      hostname.endsWith('.internal') ||
      hostname.endsWith('.local') ||
      hostname === '::1'
    ) {
      return false;
    }

    // Block 172.16.x.x - 172.31.x.x
    const parts = hostname.split('.');
    if (parts.length === 4 && parts[0] === '172') {
      const secondOctet = parseInt(parts[1], 10);
      if (secondOctet >= 16 && secondOctet <= 31) {
        return false;
      }
    }

    // AWS / GCP Metadata endpoints
    if (hostname === '169.254.169.254' || hostname === 'metadata.google.internal') {
      return false;
    }

    return true;
  } catch (e) {
    return false;
  }
}

// @ts-nocheck
import { DOMParser } from "https://deno.land/x/deno_dom/deno-dom-wasm.ts";

export interface ParsedProduct {
  nome: string | null;
  descricao: string | null;
  preco: number | null;
  moeda: string | null;
  nome_fornecedor: string | null;
  imagens: string[];
  origem_campos: Record<string, string>;
}

export function parseProductHtml(html: string, originalUrl: string): ParsedProduct {
  const doc = new DOMParser().parseFromString(html, "text/html");
  if (!doc) {
    throw new Error("Failed to parse HTML");
  }

  const result: ParsedProduct = {
    nome: null,
    descricao: null,
    preco: null,
    moeda: null,
    nome_fornecedor: null,
    imagens: [],
    origem_campos: {}
  };

  const getAbsoluteUrl = (relUrl: string) => {
    try {
      return new URL(relUrl, originalUrl).href;
    } catch {
      return relUrl;
    }
  };

  // 1. JSON-LD
  const jsonLdScripts = doc.querySelectorAll('script[type="application/ld+json"]');
  for (const script of jsonLdScripts) {
    try {
      const content = script.textContent;
      if (!content) continue;
      let data = JSON.parse(content);

      const processJsonLd = (obj: any) => {
        if (!obj) return;
        if (Array.isArray(obj)) {
          obj.forEach(processJsonLd);
          return;
        }
        if (obj['@graph'] && Array.isArray(obj['@graph'])) {
          obj['@graph'].forEach(processJsonLd);
          return;
        }

        if (obj['@type'] === 'Product') {
          if (!result.nome && obj.name) {
            result.nome = typeof obj.name === 'string' ? obj.name : obj.name[0];
            result.origem_campos['nome'] = 'json_ld';
          }
          if (!result.descricao && obj.description) {
            result.descricao = typeof obj.description === 'string' ? obj.description : obj.description[0];
            result.origem_campos['descricao'] = 'json_ld';
          }
          if (obj.image) {
            const imgs = Array.isArray(obj.image) ? obj.image : [obj.image];
            imgs.forEach((img: any) => {
              if (typeof img === 'string') {
                if (!result.imagens.includes(getAbsoluteUrl(img))) {
                  result.imagens.push(getAbsoluteUrl(img));
                }
              } else if (img && img.url) {
                if (!result.imagens.includes(getAbsoluteUrl(img.url))) {
                  result.imagens.push(getAbsoluteUrl(img.url));
                }
              }
            });
            if (result.imagens.length > 0 && !result.origem_campos['imagens']) {
              result.origem_campos['imagens'] = 'json_ld';
            }
          }

          if (obj.brand && obj.brand.name && !result.nome_fornecedor) {
            result.nome_fornecedor = typeof obj.brand.name === 'string' ? obj.brand.name : null;
            if (result.nome_fornecedor) result.origem_campos['nome_fornecedor'] = 'json_ld';
          }

          const offers = obj.offers;
          if (offers && !result.preco) {
            const offerList = Array.isArray(offers) ? offers : [offers];
            for (const offer of offerList) {
              const price = offer.price || offer.lowPrice;
              if (price !== undefined && price !== null) {
                const numPrice = parseFloat(String(price).replace(/[^0-9.]/g, ''));
                if (!isNaN(numPrice) && numPrice > 0) {
                  result.preco = numPrice;
                  result.moeda = offer.priceCurrency || 'BRL';
                  result.origem_campos['preco'] = 'json_ld';
                  result.origem_campos['moeda'] = 'json_ld';
                  break;
                }
              }
            }
          }
        }
      };

      processJsonLd(data);
    } catch (e) {
      // ignore JSON parse errors
    }
  }

  // 2. Open Graph
  if (!result.nome) {
    const ogTitle = doc.querySelector('meta[property="og:title"]');
    if (ogTitle) {
      result.nome = ogTitle.getAttribute('content');
      result.origem_campos['nome'] = 'open_graph';
    }
  }

  if (!result.descricao) {
    const ogDesc = doc.querySelector('meta[property="og:description"]');
    if (ogDesc) {
      result.descricao = ogDesc.getAttribute('content');
      result.origem_campos['descricao'] = 'open_graph';
    }
  }

  if (result.imagens.length === 0) {
    const ogImage = doc.querySelector('meta[property="og:image"]');
    if (ogImage && ogImage.getAttribute('content')) {
      result.imagens.push(getAbsoluteUrl(ogImage.getAttribute('content')!));
      result.origem_campos['imagens'] = 'open_graph';
    }
  }

  if (!result.preco) {
    const ogPrice = doc.querySelector('meta[property="product:price:amount"]');
    const ogCurrency = doc.querySelector('meta[property="product:price:currency"]');
    if (ogPrice && ogPrice.getAttribute('content')) {
      const p = parseFloat(ogPrice.getAttribute('content')!.replace(/[^0-9.]/g, ''));
      if (!isNaN(p) && p > 0) {
        result.preco = p;
        result.origem_campos['preco'] = 'open_graph';
        if (ogCurrency && ogCurrency.getAttribute('content')) {
          result.moeda = ogCurrency.getAttribute('content');
          result.origem_campos['moeda'] = 'open_graph';
        } else {
          result.moeda = 'BRL';
        }
      }
    }
  }

  // 3. Meta / Itemprop fallback
  if (!result.nome) {
    const metaTitle = doc.querySelector('title');
    if (metaTitle && metaTitle.textContent) {
      result.nome = metaTitle.textContent;
      result.origem_campos['nome'] = 'title';
    }
  }

  if (!result.descricao) {
    const metaDesc = doc.querySelector('meta[name="description"]');
    if (metaDesc) {
      result.descricao = metaDesc.getAttribute('content');
      result.origem_campos['descricao'] = 'meta';
    }
  }

  if (!result.nome_fornecedor) {
    const ogSiteName = doc.querySelector('meta[property="og:site_name"]');
    if (ogSiteName) {
      result.nome_fornecedor = ogSiteName.getAttribute('content');
      result.origem_campos['nome_fornecedor'] = 'open_graph';
    } else {
       try {
         result.nome_fornecedor = new URL(originalUrl).hostname.replace('www.', '');
         result.origem_campos['nome_fornecedor'] = 'url';
       } catch {}
    }
  }

  // Normalize
  if (result.descricao) {
    // Strip HTML tags if any sneaked in
    result.descricao = result.descricao.replace(/<[^>]*>?/gm, '').trim();
  }
  if (result.nome) {
    result.nome = result.nome.replace(/<[^>]*>?/gm, '').trim();
  }

  return result;
}
